+        let json = serde_json::to_string(&r).unwrap();
+        let value: serde_json::Value = serde_json::from_str(&json).unwrap();
+        let errors = value.get("errors").unwrap().as_array().unwrap();
+        prop_assert_eq!(errors.len(), r.errors.len(),
